type PurpleSemaphore struct {
	// ConfigMapKeyRef is a configmap selector for Semaphore configuration
	ConfigMapKeyRef *TentacledConfigMapKeyRef `json:"configMapKeyRef,omitempty"`
	// SyncDatabaseRef is a database reference for Semaphore configuration
	Database *PurpleDatabase `json:"database,omitempty"`
	// Namespace is the namespace of the configmap, default: [namespace of workflow]
	Namespace *string `json:"namespace,omitempty"`
}

// ConfigMapKeyRef is a configmap selector for Semaphore configuration
type TentacledConfigMapKeyRef struct {
	// The key to select.
	Key string `json:"key"`
	// Name of the referent.
	// This field is effectively required, but due to backwards compatibility is
	// allowed to be empty. Instances of this type with an empty value here are
	// almost certainly wrong.
	// More info: https://kubernetes.io/docs/concepts/overview/working-with-objects/names/#names
	Name *string `json:"name,omitempty"`
	// Specify whether the ConfigMap or its key must be defined
	Optional *bool `json:"optional,omitempty"`
}

// SyncDatabaseRef is a database reference for Semaphore configuration
type PurpleDatabase struct {
	Key string `json:"key"`
}

// TTLStrategy limits the lifetime of a Workflow that has finished execution depending on if
// it
// Succeeded or Failed. If this struct is set, once the Workflow finishes, it will be
// deleted after the time to live expires. If this field is unset,
// the controller config map will hold the default values.
type TTLStrategy struct {
	// SecondsAfterCompletion is the number of seconds to live after completion
	SecondsAfterCompletion *int64 `json:"secondsAfterCompletion,omitempty"`
	// SecondsAfterFailure is the number of seconds to live after failure
	SecondsAfterFailure *int64 `json:"secondsAfterFailure,omitempty"`
	// SecondsAfterSuccess is the number of seconds to live after success
	SecondsAfterSuccess *int64 `json:"secondsAfterSuccess,omitempty"`
}

