// Strategy is the strategy to use.
type ArtifactGCStrategy string

const (
	Never                      ArtifactGCStrategy = "Never"
	OnWorkflowDeletion         ArtifactGCStrategy = "OnWorkflowDeletion"
	Purple                     ArtifactGCStrategy = ""
	PurpleOnWorkflowCompletion ArtifactGCStrategy = "OnWorkflowCompletion"
)

// Operation defines the operation to apply with value and the metrics' current value
type Operation string

const (
	Add Operation = "Add"
	Set Operation = "Set"
	Sub Operation = "Sub"
)

// Strategy is the strategy to use. One of "OnPodCompletion", "OnPodSuccess",
// "OnWorkflowCompletion", "OnWorkflowSuccess". If unset, does not delete Pods
type PodGCStrategy string

const (
	Fluffy                     PodGCStrategy = ""
	FluffyOnWorkflowCompletion PodGCStrategy = "OnWorkflowCompletion"
	OnPodCompletion            PodGCStrategy = "OnPodCompletion"
	OnPodSuccess               PodGCStrategy = "OnPodSuccess"
	OnWorkflowSuccess          PodGCStrategy = "OnWorkflowSuccess"
)

// RetryPolicy is a policy of NodePhase statuses that will be retried
type RetryPolicy string

const (
	Always           RetryPolicy = "Always"
	OnError          RetryPolicy = "OnError"
	OnFailure        RetryPolicy = "OnFailure"
	OnTransientError RetryPolicy = "OnTransientError"
)

// Action is the action to perform to the resource.
// Must be one of: get, create, apply, delete, replace, patch
type Action string

const (
	Apply   Action = "apply"
	Create  Action = "create"
	Delete  Action = "delete"
	Get     Action = "get"
	Patch   Action = "patch"
	Replace Action = "replace"
)

// MergeStrategy is the strategy used to merge a patch. It defaults to "strategic"
// Must be one of: strategic, merge, json
type MergeStrategy string

const (
	JSON      MergeStrategy = "json"
	Merge     MergeStrategy = "merge"
	Strategic MergeStrategy = "strategic"
)

type MaxUnavailable struct {
	Integer *int64
	String  *string
}
